# Traditional + LLM-specific telemetry wrapper
def log_llm_metrics(prompt, response, latency, tokens_in, tokens_out):
    return {
        "latency_ms": latency,
        "total_tokens": tokens_in + tokens_out,
        "cost_usd": (tokens_in * 0.0015 + tokens_out * 0.002) / 1000
    }

# Compute entropy of feature recommendations over time to detect polarization
from scipy.stats import entropy

def detect_feedback_loop_polarization(recommended_item_counts):
    probs = np.array(recommended_item_counts) / sum(recommended_item_counts)
    # Low entropy indicates highly polarized recommendation distribution (potential feedback loop bias)
    return entropy(probs)
